#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int *a = malloc(N * sizeof(int));
        int *ans = malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        int *st = malloc(N * sizeof(int));
        int top = -1;
        for (int i = 2 * N - 1; i >= 0; --i) {
            int idx = i % N;
            while (top != -1 && a[st[top]] <= a[idx]) top--;
            if (i < N) ans[idx] = (top == -1) ? -1 : a[st[top]];
            st[++top] = idx;
        }
        for (int i = 0; i < N; ++i) printf("%d ", ans[i]);
        printf("\n");
        free(a);
        free(ans);
        free(st);
    }
    return 0;
}

