let pos = 0;
const T = Number(input[pos++]);
let output = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[pos++]);
  const a = new Array(N);
  for (let i = 0; i < N; i++) a[i] = Number(input[pos++]);
  const ans = new Array(N).fill(-1);
  const stack = [];
  for (let i = 2 * N - 1; i >= 0; i--) {
    const idx = i % N;
    while (stack.length && a[stack[stack.length - 1]] <= a[idx]) stack.pop();
    if (i < N) ans[idx] = stack.length ? a[stack[stack.length - 1]] : -1;
    stack.push(idx);
  }
  output.push(ans.join(' '));
}
